SELECT COUNT(*)
FROM ${tableName}
WHERE community_id = #{communityId}
  AND status = 'entered'

SELECT id, community_id, house_no, car_number, vehicle_type,
       enter_time, exit_time, duration, status,
       exception_reason, handler_admin_id, handle_time, handle_remark,
       create_time, update_time
FROM ${tableName}
WHERE community_id = #{communityId}
  AND car_number = #{carNumber}
  AND status = 'entered'
ORDER BY enter_time DESC
LIMIT 1

mapper.update:
UPDATE ${tableName}
SET status = #{record.status},
    exit_time = #{record.exitTime},
    duration = #{record.duration},
    update_time = NOW()
WHERE id = #{record.id}
